input.command:
python -c "
import outlines

outlines.register_filter('shout', str.upper)

@outlines.prompt
def greet(text):
    '{{ text | shout }}'

print(greet('hello'))

outlines.unregister_filter('shout')

try:
    print(greet('hello'))
except Exception as e:
    print('Expected error after unregister:', type(e).__name__)
"
